const resolveToCanonicalSkill = (raw) => DRILL_SKILL_TO_RADAR[raw] || null;

const challengeMatchesSkill = (challenge, canonicalSkill) => {
  if (!challenge || !canonicalSkill) return false;
  const tags = [...(challenge.skills || []), challenge.category].filter(Boolean);
  return tags.some(t => resolveToCanonicalSkill(t) === canonicalSkill);
};

const DRILL_DIFF_ORDER = { 'Easy': 0, 'Medium': 1, 'Hard': 2 };

// Build a focused drill queue for a single canonical skill.
// Order: unsolved (easy → hard), then previously-failed-then-solved (replay),
// then remaining solved (oldest-attempted first). Capped at `size`.
const buildDrillQueue = (
  canonicalSkill,
  allChallenges = [],
  solvedChallenges = new Set(),
  challengeAttempts = [],
  opts = {}
) => {
  const size = opts.size != null ? opts.size : DRILL_SIZE;
  const solvedSet = solvedChallenges instanceof Set ? solvedChallenges : new Set(solvedChallenges);

  const matching = allChallenges.filter(c => challengeMatchesSkill(c, canonicalSkill));
  if (matching.length === 0) return [];

  const failedIds = new Set(
    challengeAttempts.filter(a => a && a.success === false).map(a => a.challengeId)
  );
  const latestAttemptTs = {};
  challengeAttempts.forEach(a => {
    if (!a) return;
    const ts = a.timestamp || 0;
    if (!latestAttemptTs[a.challengeId] || ts > latestAttemptTs[a.challengeId]) {
      latestAttemptTs[a.challengeId] = ts;
    }
  });

  const byDiff = (a, b) => (DRILL_DIFF_ORDER[a.difficulty] != null ? DRILL_DIFF_ORDER[a.difficulty] : 1)
    - (DRILL_DIFF_ORDER[b.difficulty] != null ? DRILL_DIFF_ORDER[b.difficulty] : 1);

  const unsolved = matching.filter(c => !solvedSet.has(c.id)).sort(byDiff);
  const reviewFailed = matching
    .filter(c => solvedSet.has(c.id) && failedIds.has(c.id))
    .sort((a, b) => {
      const d = byDiff(a, b);
      if (d !== 0) return d;
      return (latestAttemptTs[a.id] || 0) - (latestAttemptTs[b.id] || 0);
    });
  const otherSolved = matching
    .filter(c => solvedSet.has(c.id) && !failedIds.has(c.id))
    .sort((a, b) => (latestAttemptTs[a.id] || 0) - (latestAttemptTs[b.id] || 0));

  const seen = new Set();
  const out = [];
  for (const c of [...unsolved, ...reviewFailed, ...otherSolved]) {
    if (seen.has(c.id)) continue;
    seen.add(c.id);
    out.push(c);
    if (out.length >= size) break;
  }
  return out;
};

// Calculate recommended difficulty based on challenge performance
const calculateRecommendedDifficulty = (solvedChallenges, allChallenges, challengeAttempts = []) => {
  if (!allChallenges || allChallenges.length === 0) return 'Easy';
  
  // Count solved by difficulty
  const stats = {
    'Easy': { solved: 0, total: 0 },
    'Medium': { solved: 0, total: 0 },
    'Hard': { solved: 0, total: 0 }
  };
  
  allChallenges.forEach(c => {
    if (stats[c.difficulty]) {
      stats[c.difficulty].total++;
      if (solvedChallenges.has(c.id)) {
        stats[c.difficulty].solved++;
      }
    }
  });

  // Calculate success rates
  const easyRate = stats.Easy.total > 0 ? stats.Easy.solved / stats.Easy.total : 0;
  const mediumRate = stats.Medium.total > 0 ? stats.Medium.solved / stats.Medium.total : 0;
  const hardRate = stats.Hard.total > 0 ? stats.Hard.solved / stats.Hard.total : 0;
  
  // Determine recommendation
  // Need minimum 3 solved and >50% rate to move up
  if (stats.Hard.solved >= 2 && hardRate >= 0.4) {
    return 'Hard';
  } else if (stats.Medium.solved >= 3 && mediumRate >= 0.5) {
    return 'Hard';
  } else if (stats.Easy.solved >= 3 && easyRate >= 0.6) {
    return 'Medium';
  }
  return 'Easy';
};

// Check if user is struggling (3+ fails in last 5 daily challenges)
const checkIfStruggling = (dailyHistory) => {
  if (!dailyHistory || dailyHistory.length < 3) return { struggling: false };
  
  const recent = dailyHistory.slice(-5);
  const fails = recent.filter(d => !d.success).length;
  
  if (fails >= 3) {
    // Find most common failed topic
    const failedTopics = recent.filter(d => !d.success).map(d => d.topic);
    const topicCounts = {};
    failedTopics.forEach(t => { topicCounts[t] = (topicCounts[t] || 0) + 1; });
    const struggleTopic = Object.entries(topicCounts).sort((a, b) => b[1] - a[1])[0]?.[0];
    
    return { struggling: true, topic: struggleTopic, failCount: fails };
  }
  
  return { struggling: false };
};

// Get topic performance stats for weekly report
const getTopicStats = (challengeAttempts, solvedChallenges, allChallenges) => {
  const topicStats = {};
  
  // Initialize from all challenges
  allChallenges.forEach(c => {
    const topic = c.topic || detectSqlTopic(c.solution);
    if (!topicStats[topic]) {
      topicStats[topic] = { attempts: 0, successes: 0, challenges: [], solved: 0, total: 0 };
    }
    topicStats[topic].total++;
    if (solvedChallenges.has(c.id)) {
      topicStats[topic].solved++;
    }
  });
  
  // Add attempt data
  challengeAttempts.forEach(a => {
    const topic = a.topic;
    if (!topicStats[topic]) {
      topicStats[topic] = { attempts: 0, successes: 0, challenges: [], solved: 0, total: 0 };
    }
    topicStats[topic].attempts++;
    if (a.success) topicStats[topic].successes++;
  });
  
  // Calculate rates and sort
  return Object.entries(topicStats)
    .map(([topic, stats]) => ({
      topic,
      ...stats,
      successRate: stats.attempts > 0 ? Math.round((stats.successes / stats.attempts) * 100) : (stats.solved > 0 ? 100 : 0),
      coverage: stats.total > 0 ? Math.round((stats.solved / stats.total) * 100) : 0
    }))
    .sort((a, b) => b.successRate - a.successRate);
};

